import java.io.*;

// FileOutputStreamでファイルに書き込み
// 例外が発生する可能性がある処理
try (FileOutputStream fos = new FileOutputStream("output.dat")) {
    fos.write(65);  // 'A'のASCIIコード
    fos.write(66);  // 'B'
    byte[] data = {67, 68, 69}; // C, D, E
    fos.write(data);
} // 自動的にclose()される

// FileInputStreamでファイルから読み込み
// 例外が発生する可能性がある処理
try (FileInputStream fis = new FileInputStream("output.dat")) {
    int b;
    // 条件が成り立つ間、繰り返す
    while ((b = fis.read()) != -1) {
        System.out.print((char) b); // ABCDE
    }
}

// バッファ付きで効率的に読み込み
// 例外が発生する可能性がある処理
try (BufferedInputStream bis = new BufferedInputStream(
        new FileInputStream("output.dat"))) {
    byte[] buffer = new byte[1024];
    // 変数の宣言と初期化
    int len = bis.read(buffer);
    System.out.println(new String(buffer, 0, len)); // ABCDE
}

