import java.io.*;

// 基本的なtry-with-resources
// 例外が発生する可能性がある処理
try (FileReader fr = new FileReader("input.txt");
     BufferedReader br = new BufferedReader(fr)) {
    System.out.println(br.readLine());
} // br → fr の順でclose()される

// Java 9以降：事前宣言した変数の使用
FileReader fr = new FileReader("input.txt");
BufferedReader br = new BufferedReader(fr);
// 例外が発生する可能性がある処理
try (br) {  // 実質的final変数
    System.out.println(br.readLine());
}

// catch/finallyも使用可能
// 例外が発生する可能性がある処理
try (FileWriter fw = new FileWriter("log.txt")) {
    fw.write("ログメッセージ");
} catch (IOException e) {
    System.err.println("書き込みエラー: " + e.getMessage());
} finally {
    System.out.println("処理完了");
}

