import java.nio.file.*;
import java.io.IOException;

// list()：直下のエントリのみ
try (var stream = Files.list(Path.of("src"))) {
    stream.forEach(System.out::println);
}
// 出力例:
// src/main
// src/test
// src/App.java

// walk()：再帰的に全ファイル走査
try (var stream = Files.walk(Path.of("src"))) {
    stream.filter(Files::isRegularFile)
          .forEach(System.out::println);
}
// 出力例:
// src/App.java
// src/main/Main.java
// src/test/TestMain.java

// maxDepth指定
try (var stream = Files.walk(Path.of("src"), 1)) {
    stream.forEach(System.out::println);
}
// depth=1: srcディレクトリ自身と直下のエントリのみ

import java.nio.file.*;
import java.nio.file.attribute.*;

// find()：条件に一致するファイルを検索
// 例外が発生する可能性がある処理
try (var stream = Files.find(Path.of("src"), 10,
        (path, attrs) -> attrs.isRegularFile()
            && path.toString().endsWith(".java"))) {
    stream.forEach(System.out::println);
}

// DirectoryStream：globパターンでフィルタ
// 例外が発生する可能性がある処理
try (DirectoryStream<Path> ds = Files.newDirectoryStream(
        Path.of("src"), "*.java")) {
    // 拡張for文（コレクションの全要素を順番に処理）
    for (Path p : ds) {
        System.out.println(p.getFileName());
    }
}

// DirectoryStream：複数パターン
// 例外が発生する可能性がある処理
try (DirectoryStream<Path> ds = Files.newDirectoryStream(
        Path.of("docs"), "*.{txt,md,csv}")) {
    for (Path p : ds) {
        System.out.println(p);
    }
}

import java.nio.file.*;
import java.util.stream.*;

// ファイルの各行をStreamとして処理
try (Stream<String> lines = Files.lines(Path.of("data.csv"))) {
    lines.filter(line -> !line.startsWith("#"))
         .map(String::trim)
         .forEach(System.out::println);
}

// 行数をカウント
try (Stream<String> lines = Files.lines(Path.of("log.txt"))) {
    long count = lines.filter(l -> l.contains("ERROR")).count();
    System.out.println("エラー行数: " + count);
}

// 結果をリストに収集
try (Stream<String> lines = Files.lines(Path.of("names.txt"))) {
    var sorted = lines.sorted()
                      .distinct()
                      .collect(Collectors.toList());
    sorted.forEach(System.out::println);
}

